module RefModule(
    input  VPWR,
    input  UDP_IN,
    input  CLK,
    output UDP_OUT
);reg pwrgood;

    always @(posedge CLK) begin
        if (UDP_IN) begin
            pwrgood <= 0;
        end else begin
            pwrgood <= VPWR;
        end
    end

    wire __UDP_OUT_tmp = pwrgood;
    assign UDP_OUT = __UDP_OUT_tmp;

endmodule
